import { useState } from 'react'
import { useQuery, useMutation } from '../hooks/useQuery'
import { eventosService } from '../services/eventosService'
import { faturasService } from '../services/faturasService'
import { clientesService } from '../services/clientesService'

const fmt = (v) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v || 0)

export default function ReceberPage() {
  const [aba, setAba] = useState('faltaFaturar')
    const [eventoEditando, setEventoEditando] = useState(null)
      const { data, refetch } = useQuery(() => eventosService.porStatus(), [])
        const { data: clientes } = useQuery(() => clientesService.listar(), [])
          const confirmarRecebimento = useMutation((faturaId) => faturasService.marcarRecebida(faturaId))
            const atualizarEvento = useMutation(({ id, dados }) => eventosService.atualizar(id, dados))

              const abas = [
                  { key: 'faltaFaturar', label: 'Faturar', cor: 'text-blue-600' },
                      { key: 'aguardando',   label: 'Aguardando', cor: 'text-orange-500' },
                          { key: 'recebido',     label: 'Recebido', cor: 'text-green-600' },
                            ]

                              const lista = data?.[aba] || []

                                const totais = {
                                    faltaFaturar: data?.faltaFaturar?.reduce((a, e) => a + (e.valor_saldo || e.valor_total || 0), 0) || 0,
                                        aguardando: data?.aguardando?.reduce((a, e) => a + (e.valor_saldo || e.valor_total || 0), 0) || 0,
                                            recebido: data?.recebido?.reduce((a, e) => a + (e.valor_total || 0), 0) || 0,
                                              }

                                                const handleConfirmar = async (faturaId) => {
                                                    await confirmarRecebimento.mutate(faturaId)
                                                        await refetch()
                                                          }

                                                            const handleSalvarEdicao = async (dados) => {
                                                                await atualizarEvento.mutate({ id: eventoEditando.id, dados })
                                                                    setEventoEditando(null)
                                                                        await refetch()
                                                                          }

                                                                            if (eventoEditando) {
                                                                                return (
                                                                                      <EditarEventoForm
                                                                                              evento={eventoEditando}
                                                                                                      clientes={clientes || []}
                                                                                                              onSalvar={handleSalvarEdicao}
                                                                                                                      onCancelar={() => setEventoEditando(null)}
                                                                                                                            />
                                                                                                                                )
                                                                                                                                  }

                                                                                                                                    return (
                                                                                                                                        <div className="flex flex-col h-full">
                                                                                                                                              <div className="flex border-b border-gray-200 bg-white px-4">
                                                                                                                                                      {abas.map(a => (
                                                                                                                                                                <button
                                                                                                                                                                            key={a.key}
                                                                                                                                                                                        onClick={() => setAba(a.key)}
                                                                                                                                                                                                    className={`flex-1 py-3 text-xs font-semibold border-b-2 transition-colors ${
                                                                                                                                                                                                                  aba === a.key ? `border-orange-500 ${a.cor}` : 'border-transparent text-gray-400'
                                                                                                                                                                                                                              }`}
                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                    {a.label}
                                                                                                                                                                                                                                                                <span className={`ml-1 ${aba === a.key ? '' : 'text-gray-300'}`}>
                                                                                                                                                                                                                                                                              ({data?.[a.key]?.length || 0})
                                                                                                                                                                                                                                                                                          </span>
                                                                                                                                                                                                                                                                                                    </button>
                                                                                                                                                                                                                                                                                                            ))}
                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                        <div className="px-4 py-3 bg-white border-b border-gray-100">
                                                                                                                                                                                                                                                                                                                                <p className="text-xs text-gray-500">Total em {abas.find(a => a.key === aba)?.label.toLowerCase()}</p>
                                                                                                                                                                                                                                                                                                                                        <p className={`text-xl font-bold ${aba === 'faltaFaturar' ? 'text-blue-600' : aba === 'aguardando' ? 'text-orange-500' : 'text-green-600'}`}>{fmt(totais[aba])}</p>
                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                    <div className="flex-1 overflow-y-auto p-4 space-y-3">
                                                                                                                                                                                                                                                                                                                                                            {lista.length === 0 ? (
                                                                                                                                                                                                                                                                                                                                                                      <div className="flex flex-col items-center justify-center h-40 text-gray-400">
                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-sm">Nada aqui por enquanto</p>
                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                    ) : (
                                                                                                                                                                                                                                                                                                                                                                                                              lista.map(e => (
                                                                                                                                                                                                                                                                                                                                                                                                                          <EventoCard key={e.id} evento={e} aba={aba} onConfirmar={handleConfirmar} onEditar={setEventoEditando} />
                                                                                                                                                                                                                                                                                                                                                                                                                                    ))
                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                        )
                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                        function EventoCard({ evento: e, aba, onConfirmar, onEditar }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                          const [confirmando, setConfirmando] = useState(false)
                                                                                                                                                                                                                                                                                                                                                                                                                                                            const handleConfirmar = async () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                setConfirmando(true)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try { await onConfirmar(e.faturas?.id) } finally { setConfirmando(false) }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="card">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="flex justify-between items-start mb-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="flex-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="font-semibold text-gray-800">{e.clientes?.nome || '-'}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-xs text-gray-500">{new Date(e.data_evento + 'T00:00:00').toLocaleDateString('pt-BR')} · {e.local || '-'}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="text-right ml-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="font-bold text-gray-800">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(e.valor_saldo || e.valor_total || 0)}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {e.pax && <p className="text-xs text-gray-400">{e.pax} convidados</p>}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {aba === 'aguardando' && e.faturas && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex items-center justify-between mt-2 pt-2 border-t border-gray-100">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-xs text-gray-500">Fatura {e.faturas.numero}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {e.faturas.vencimento && <p className="text-xs text-gray-400">Vence em {new Date(e.faturas.vencimento + 'T00:00:00').toLocaleDateString('pt-BR')}</p>}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button onClick={handleConfirmar} disabled={confirmando} className="text-xs bg-green-500 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg transition-colors disabled:opacity-60">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {confirmando ? '...' : 'Confirmar recebimento'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {aba === 'recebido' && e.faturas?.recebida_em && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-xs text-green-600 mt-1">Recebido em {new Date(e.faturas.recebida_em).toLocaleDateString('pt-BR')}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="mt-2 pt-2 border-t border-gray-100">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button onClick={() => onEditar(e)} className="text-xs text-orange-500 hover:text-orange-600 font-medium">Editar evento</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      function EditarEventoForm({ evento, clientes, onSalvar, onCancelar }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const [form, setForm] = useState({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            cliente_id: evento.cliente_id || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                data_evento: evento.data_evento || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    local: evento.local || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        pax: evento.pax || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            tipo_evento: evento.tipo_evento || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cardapio: evento.cardapio || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    valor_total: evento.valor_total || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        valor_sinal: evento.valor_sinal || '',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            status: evento.status || 'confirmado',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const [loading, setLoading] = useState(false)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const handleSubmit = async (ev) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ev.preventDefault()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setLoading(true)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try { await onSalvar({ ...form, pax: parseInt(form.pax) || null, valor_total: parseFloat(form.valor_total) || 0, valor_sinal: parseFloat(form.valor_sinal) || 0 }) }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    finally { setLoading(false) }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="p-4 overflow-y-auto h-full pb-8">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <button onClick={onCancelar} className="text-orange-500 text-sm font-medium mb-4 block">Voltar</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <h2 className="text-xl font-bold text-gray-800 mb-4">Editar Evento</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <form onSubmit={handleSubmit} className="space-y-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div><label className="label">CLIENTE</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <select value={form.cliente_id} onChange={e => set('cliente_id', e.target.value)} className="input" required>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <option value="">Selecione...</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </select></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div><label className="label">DATA DO EVENTO</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <input type="date" value={form.data_evento} onChange={e => set('data_evento', e.target.value)} className="input" required /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div><label className="label">LOCAL</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <input type="text" value={form.local} onChange={e => set('local', e.target.value)} className="input" /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="grid grid-cols-2 gap-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div><label className="label">CONVIDADOS</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <input type="number" value={form.pax} onChange={e => set('pax', e.target.value)} className="input" min="1" /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div><label className="label">STATUS</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <select value={form.status} onChange={e => set('status', e.target.value)} className="input">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <option value="confirmado">Confirmado</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <option value="aguardando">Aguardando</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <option value="faturado">Faturado</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <option value="recebido">Recebido</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <option value="cancelado">Cancelado</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </select></div></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div><label className="label">VALOR TOTAL (R$)</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <input type="number" step="0.01" value={form.valor_total} onChange={e => set('valor_total', e.target.value)} className="input" /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div><label className="label">SINAL (R$)</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <input type="number" step="0.01" value={form.valor_sinal} onChange={e => set('valor_sinal', e.target.value)} className="input" /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div><label  className="label">TIPO DE EVENTO</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <input type="text" value={form.tipo_evento} onChange={e => set('tipo_evento', e.target.value)} className="input" /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div><label className="label">CARDAPIO / OBSERVACOES</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <textarea value={form.cardapio} onChange={e => set('cardapio', e.target.value)} className="input" rows={3} /></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button type="submit" disabled={loading} className="btn-primary w-full">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {loading ? 'Salvando...' : 'Salvar alteracoes'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }